export type Project = {
  id: string;
  title: string;
  description: string;
  fullDescription: string;
  thumbnail: string;
  images: string[];
  tags: string[];
  demoUrl: string | null;
  sourceUrl: string | null;
  dateAdded: string;
};

export type ProjectInput = {
  title: string;
  description: string;
  fullDescription?: string;
  thumbnail?: string;
  images?: string[];
  tags?: string[];
  demoUrl?: string | null;
  sourceUrl?: string | null;
};

export type SortOption = "date-desc" | "date-asc" | "alpha-asc" | "alpha-desc";

export type ListOptions = {
  tag?: string;
  search?: string;
  sort?: SortOption;
};

export type GalleryViewState = {
  activeTag: string;
  search: string;
  sort: SortOption;
  allTags: string[];
};

import type { Project, ProjectInput, ListOptions, SortOption } from "./types";

const DATA_PATH = `${import.meta.dir}/data/projects.json`;

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2));
};

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects];
  switch (sort) {
    case "date-desc":
      return sorted.sort((a, b) => b.dateAdded.localeCompare(a.dateAdded));
    case "date-asc":
      return sorted.sort((a, b) => a.dateAdded.localeCompare(b.dateAdded));
    case "alpha-asc":
      return sorted.sort((a, b) => a.title.localeCompare(b.title));
    case "alpha-desc":
      return sorted.sort((a, b) => b.title.localeCompare(a.title));
    default:
      return sorted;
  }
};

export const listProjects = async (options: ListOptions = {}): Promise<Project[]> => {
  const { tag, search, sort = "date-desc" } = options;
  let projects = await readProjects();

  if (tag) {
    const lowerTag = tag.toLowerCase();
    projects = projects.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === lowerTag)
    );
  }

  if (search) {
    const lowerSearch = search.toLowerCase();
    projects = projects.filter((p) =>
      p.title.toLowerCase().includes(lowerSearch)
    );
  }

  return sortProjects(projects, sort);
};

export const getProject = async (id: string): Promise<Project | null> => {
  const projects = await readProjects();
  return projects.find((p) => p.id === id) ?? null;
};

export const addProject = async (input: ProjectInput): Promise<Project> => {
  const projects = await readProjects();
  const id = input.title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");

  const project: Project = {
    id,
    title: input.title,
    description: input.description,
    fullDescription: input.fullDescription ?? input.description,
    thumbnail: input.thumbnail ?? "",
    images: input.images ?? [],
    tags: input.tags ?? [],
    demoUrl: input.demoUrl ?? null,
    sourceUrl: input.sourceUrl ?? null,
    dateAdded: new Date().toISOString().slice(0, 10),
  };

  projects.push(project);
  await writeProjects(projects);
  return project;
};

export const updateProject = async (
  id: string,
  updates: Partial<ProjectInput>
): Promise<Project | null> => {
  const projects = await readProjects();
  const index = projects.findIndex((p) => p.id === id);
  if (index === -1) return null;

  const existing = projects[index];
  const updated: Project = {
    ...existing,
    ...updates,
    id: existing.id,
    dateAdded: existing.dateAdded,
  };

  projects[index] = updated;
  await writeProjects(projects);
  return updated;
};

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await readProjects();
  const filtered = projects.filter((p) => p.id !== id);
  if (filtered.length === projects.length) return false;
  await writeProjects(filtered);
  return true;
};

export const getAllTags = async (): Promise<string[]> => {
  const projects = await readProjects();
  const tagSet = new Set<string>();
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t);
    }
  }
  return [...tagSet].sort((a, b) => a.localeCompare(b));
};

