import { galleryStyles as gs, detailStyles as ds } from "./styles";

const styleAttr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${prop}:${typeof v === "number" ? `${v}px` : v}`;
    })
    .join(";");

const TagPill = (tag: string, active: boolean) =>
  h(
    "a",
    {
      href: active ? "?tag=" : `?tag=${encodeURIComponent(tag)}`,
      style: styleAttr(active ? gs.tagActive : gs.tag),
      "p-trigger": "click:filterTag",
      "data-tag": tag,
    },
    tag
  );

const ProjectCard = (project: Project) =>
  h(
    "a",
    {
      href: `?view=detail&id=${project.id}`,
      style: styleAttr(gs.card),
      "p-trigger": "click:viewProject",
      "data-id": project.id,
    },
    project.thumbnail
      ? h("img", {
          src: project.thumbnail,
          alt: project.title,
          style: styleAttr(gs.cardThumb),
          loading: "lazy",
        })
      : h("div", { style: styleAttr(gs.cardThumbPlaceholder) }, "\u{1F4C1}"),
    h(
      "div",
      { style: styleAttr(gs.cardBody) },
      h("h3", { style: styleAttr(gs.cardTitle) }, project.title),
      h("p", { style: styleAttr(gs.cardDesc) }, project.description),
      h(
        "div",
        { style: styleAttr(gs.cardTags) },
        ...project.tags.map((t) =>
          h("span", { style: styleAttr(gs.cardTag) }, t)
        )
      ),
      h(
        "div",
        { style: styleAttr(gs.cardLinks) },
        ...[
          project.demoUrl
            ? h(
                "span",
                {
                  style: styleAttr(gs.cardLink),
                },
                "\u{25B6} Demo"
              )
            : null,
          project.sourceUrl
            ? h(
                "span",
                {
                  style: styleAttr(gs.cardLink),
                },
                "\u{2630} Source"
              )
            : null,
        ].filter(Boolean)
      )
    )
  );

const EmptyState = (search: string, tag: string) => {
  const messages: string[] = [];
  if (search) messages.push(`matching "${search}"`);
  if (tag) messages.push(`tagged "${tag}"`);
  const suffix = messages.length ? ` ${messages.join(" and ")}` : "";
  return h(
    "div",
    { style: styleAttr(gs.emptyState) },
    h("div", { style: styleAttr(gs.emptyIcon) }, "\u{1F50D}"),
    h("p", { style: styleAttr(gs.emptyText) }, `No projects found${suffix}.`)
  );
};

export const renderGallery = (
  projects: Project[],
  state: GalleryViewState
): string => {
  const { activeTag, search, sort, allTags } = state;

  const sortOptions = [
    { value: "date-desc", label: "Newest First" },
    { value: "date-asc", label: "Oldest First" },
    { value: "alpha-asc", label: "A \u2192 Z" },
    { value: "alpha-desc", label: "Z \u2192 A" },
  ];

  const template = h(
    "div",
    { style: styleAttr(gs.container) },
    h(
      "header",
      { style: styleAttr(gs.header) },
      h("h1", { style: styleAttr(gs.title) }, "Portfolio"),
      h("p", { style: styleAttr(gs.subtitle) }, "A collection of my projects and experiments")
    ),
    h(
      "div",
      { style: styleAttr(gs.controls) },
      h("input", {
        type: "text",
        placeholder: "Search projects\u2026",
        value: search,
        style: styleAttr(gs.searchInput),
        "p-trigger": "input:searchProjects",
        "p-target": "searchInput",
      }),
      h(
        "select",
        {
          style: styleAttr(gs.sortSelect),
          "p-trigger": "change:sortProjects",
          "p-target": "sortSelect",
        },
        ...sortOptions.map((opt) =>
          h(
            "option",
            {
              value: opt.value,
              ...(opt.value === sort ? { selected: "selected" } : {}),
            },
            opt.label
          )
        )
      )
    ),
    allTags.length > 0
      ? h(
          "div",
          { style: styleAttr(gs.tagBar), "p-target": "tagBar" },
          h(
            "a",
            {
              href: "?tag=",
              style: styleAttr(!activeTag ? gs.tagActive : gs.tag),
              "p-trigger": "click:filterTag",
              "data-tag": "",
            },
            "All"
          ),
          ...allTags.map((t) => TagPill(t, t === activeTag))
        )
      : null,
    projects.length > 0
      ? h(
          "div",
          { style: styleAttr(gs.grid), "p-target": "projectGrid" },
          ...projects.map(ProjectCard)
        )
      : EmptyState(search, activeTag)
  );

  return String(template);
};

const CarouselImage = (src: string, index: number, active: boolean) =>
  h("img", {
    src,
    alt: `Screenshot ${index + 1}`,
    style: styleAttr({
      ...ds.carouselImage,
      display: active ? "block" : "none",
    }),
    "data-index": String(index),
    "p-target": `slide-${index}`,
  });

const Thumbnail = (src: string, index: number, active: boolean) =>
  h("img", {
    src,
    alt: `Thumbnail ${index + 1}`,
    style: styleAttr(active ? ds.thumbActive : ds.thumb),
    "data-index": String(index),
    "p-trigger": "click:goToSlide",
  });

