    ),
    h("h1", { style: styleAttr(ds.title) }, project.title),
    h(
      "div",
      { style: styleAttr(ds.tags) },
      ...project.tags.map((t) =>
        h("span", { style: styleAttr(ds.tag) }, t)
      )
    ),
    h("div", { style: styleAttr(ds.meta) }, `Added ${dateFormatted}`),
    h(
      "div",
      { style: styleAttr(ds.links) },
      ...[
        project.demoUrl
          ? h(
              "a",
              {
                href: project.demoUrl,
                target: "_blank",
                rel: "noopener noreferrer",
                style: styleAttr({ ...ds.linkButton, ...ds.demoButton }),
              },
              "\u{25B6} Live Demo"
            )
          : null,
        project.sourceUrl
          ? h(
              "a",
              {
                href: project.sourceUrl,
                target: "_blank",
                rel: "noopener noreferrer",
                style: styleAttr({ ...ds.linkButton, ...ds.sourceButton }),
              },
              "\u{2630} Source Code"
            )
          : null,
      ].filter(Boolean)
    ),
    h("div", { style: styleAttr(ds.description) }, project.fullDescription),
    hasImages
      ? h(
          "div",
          { style: styleAttr(ds.carouselSection) },
          h("h2", { style: styleAttr(ds.carouselTitle) }, "Screenshots"),
          h(
            "div",
            {
              style: styleAttr(ds.carousel),
              "p-target": "carousel",
            },
            ...project.images.map((src, i) => CarouselImage(src, i, i === 0)),
            project.images.length > 1
              ? h(Fragment, {},
                  h(
                    "button",
                    {
                      style: styleAttr({ ...ds.carouselNav, ...ds.carouselPrev }),
                      "p-trigger": "click:prevSlide",
                      "p-target": "prevBtn",
                    },
                    "\u2039"
                  ),
                  h(
                    "button",
                    {
                      style: styleAttr({ ...ds.carouselNav, ...ds.carouselNext }),
                      "p-trigger": "click:nextSlide",
                      "p-target": "nextBtn",
                    },
                    "\u203A"
                  )
                )
              : null
          ),
          project.images.length > 1
            ? h(
                "div",
                { style: styleAttr(ds.thumbnails), "p-target": "thumbnails" },
                ...project.images.map((src, i) => Thumbnail(src, i, i === 0))
              )
            : null
        )
      : null,
    hasImages
      ? h(
          "div",
          {
            style: styleAttr({ ...ds.lightboxOverlay, display: "none" }),
            "p-target": "lightbox",
            "p-trigger": "click:closeLightbox",
          },
          h(
            "button",
            {
              style: styleAttr(ds.lightboxClose),
              "p-trigger": "click:closeLightbox",
            },
            "\u00D7"
          ),
          h("img", {
            src: project.images[0],
            alt: project.title,
            style: styleAttr(ds.lightboxImage),
            "p-target": "lightboxImage",
          })
        )
      : null
  );

  return String(template);
};

