const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;

  // API routes
  if (path.startsWith("/api/")) {
    return handleApi(req, url);
  }

  // Page routes
  const query = parseQuery(url);

  if (query.view === "detail" && query.id) {
    const project = await getProject(query.id);
    return htmlResponse(renderDetail(project));
  }

  const options: ListOptions = {
    tag: query.tag || undefined,
    search: query.search || undefined,
    sort: query.sort,
  };

  const [projects, allTags] = await Promise.all([
    listProjects(options),
    getAllTags(),
  ]);

  return htmlResponse(
    renderGallery(projects, {
      activeTag: query.tag,
      search: query.search,
      sort: query.sort,
      allTags,
    })
  );
};

const handleApi = async (req: Request, url: URL): Promise<Response> => {
  const path = url.pathname;
  const method = req.method;

  // GET /api/projects — list projects
  if (path === "/api/projects" && method === "GET") {
    const tag = url.searchParams.get("tag") || undefined;
    const search = url.searchParams.get("search") || undefined;
    const sort = (url.searchParams.get("sort") as SortOption) || "date-desc";
    const projects = await listProjects({ tag, search, sort });
    return jsonResponse(projects);
  }

  // GET /api/projects/:id — single project
  if (path.startsWith("/api/projects/") && method === "GET") {
    const id = path.slice("/api/projects/".length);
    const project = await getProject(id);
    if (!project) return jsonResponse({ error: "Not found" }, 404);
    return jsonResponse(project);
  }

  // POST /api/projects — create project
  if (path === "/api/projects" && method === "POST") {
    const body = await req.json();
    const project = await addProject(body);
    return jsonResponse(project, 201);
  }

  // PATCH /api/projects/:id — update project
  if (path.startsWith("/api/projects/") && method === "PATCH") {
    const id = path.slice("/api/projects/".length);
    const body = await req.json();
    const project = await updateProject(id, body);
    if (!project) return jsonResponse({ error: "Not found" }, 404);
    return jsonResponse(project);
  }

  // DELETE /api/projects/:id — delete project
  if (path.startsWith("/api/projects/") && method === "DELETE") {
    const id = path.slice("/api/projects/".length);
    const ok = await deleteProject(id);
    if (!ok) return jsonResponse({ error: "Not found" }, 404);
    return jsonResponse({ deleted: true });
  }

  // GET /api/tags — all tags
  if (path === "/api/tags" && method === "GET") {
    const tags = await getAllTags();
    return jsonResponse(tags);
  }

  return jsonResponse({ error: "Not found" }, 404);
};

