import type { GalleryFilters, SortField, SortDirection } from './types'
import { filterAndSortProjects, getAllTags, getProjectById } from './data'
import { renderGalleryPage, renderDetailPage } from './render'

const BASE_URL = '/portfolio'

const parseSort = (raw: string | null): { field: SortField; direction: SortDirection } => {
  if (!raw) return { field: 'dateAdded', direction: 'desc' }
  const [field, direction] = raw.split(':')
  const validFields: SortField[] = ['dateAdded', 'title']
  const validDirs: SortDirection[] = ['asc', 'desc']
  return {
    field: validFields.includes(field as SortField) ? (field as SortField) : 'dateAdded',
    direction: validDirs.includes(direction as SortDirection) ? (direction as SortDirection) : 'desc',
  }
}

const wrapHtml = (title: string, body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; }
    a:hover { opacity: 0.85; }
    img { max-width: 100%; }
    @media (max-width: 480px) {
      [style*="grid-template-columns"] {
        grid-template-columns: 1fr !important;
      }
    }
  </style>
</head>
<body>${body}</body>
</html>`

const handleGallery = async (url: URL): Promise<Response> => {
  const search = url.searchParams.get('search') || ''
  const tag = url.searchParams.get('tag') || ''
  const { field: sortField, direction: sortDirection } = parseSort(url.searchParams.get('sort'))

  const filters: GalleryFilters = { search, tag, sortField, sortDirection }
  const [projects, allTags] = await Promise.all([
    filterAndSortProjects(filters),
    getAllTags(),
  ])

  const ssr = createSSR()
  const content = renderGalleryPage(projects, allTags, filters, BASE_URL)
  const body = ssr(content)
  return new Response(wrapHtml('Portfolio Gallery', body), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleProjectDetail = async (projectId: string, url: URL): Promise<Response> => {
  const project = await getProjectById(projectId)
  if (!project) {
    return new Response('Project not found', { status: 404 })
  }

  const imgParam = url.searchParams.get('img')
  const lightboxIndex = imgParam !== null
    ? Math.max(0, Math.min(parseInt(imgParam, 10) || 0, project.images.length - 1))
    : 0

  const ssr = createSSR()
  const content = renderDetailPage(project, lightboxIndex, BASE_URL)
  const body = ssr(content)
  return new Response(wrapHtml(`${project.title} — Portfolio`, body), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleApiProjects = async (url: URL): Promise<Response> => {
  const search = url.searchParams.get('search') || ''
  const tag = url.searchParams.get('tag') || ''
  const { field: sortField, direction: sortDirection } = parseSort(url.searchParams.get('sort'))
  const filters: GalleryFilters = { search, tag, sortField, sortDirection }
  const projects = await filterAndSortProjects(filters)
  return Response.json(projects)
}

const handleApiProjectDetail = async (projectId: string): Promise<Response> => {
  const project = await getProjectById(projectId)
  if (!project) {
    return Response.json({ error: 'Project not found' }, { status: 404 })
  }
  return Response.json(project)
}

const handleApiTags = async (): Promise<Response> => {
  const tags = await getAllTags()
  return Response.json(tags)
}

export const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  // HTML routes
  if (path === BASE_URL || path === `${BASE_URL}/`) {
    return handleGallery(url)
  }

  const detailMatch = path.match(new RegExp(`^${BASE_URL}/project/([\\w-]+)$`))
  if (detailMatch) {
    return handleProjectDetail(detailMatch[1], url)
  }

  // JSON API routes
  if (path === `${BASE_URL}/api/projects`) {
    return handleApiProjects(url)
  }

  const apiDetailMatch = path.match(new RegExp(`^${BASE_URL}/api/projects/([\\w-]+)$`))
  if (apiDetailMatch) {
    return handleApiProjectDetail(apiDetailMatch[1])
  }

  if (path === `${BASE_URL}/api/tags`) {
    return handleApiTags()
  }

  return new Response('Not Found', { status: 404 })
}

