export const sortProjects = (projects: Project[], sortBy: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sortBy) {
    case "date-desc":
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case "date-asc":
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case "alpha-asc":
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case "alpha-desc":
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const filterProjects = (
  projects: Project[],
  searchQuery: string,
  activeTag: string | null,
): Project[] => {
  let result = projects

  if (searchQuery.trim()) {
    const query = searchQuery.toLowerCase()
    result = result.filter((p) => p.title.toLowerCase().includes(query))
  }

  if (activeTag) {
    result = result.filter((p) => p.tags.includes(activeTag))
  }

  return result
}

export const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

import type { GalleryState, GalleryAction, Project } from "./types"

export const reduce = (state: GalleryState, action: GalleryAction): GalleryState => {
  switch (action.type) {
    case "search":
      return { ...state, searchQuery: action.query }

    case "filter-tag":
      return {
        ...state,
        activeTag: action.tag === state.activeTag ? null : action.tag,
      }

    case "sort":
      return { ...state, sortBy: action.sortBy }

    case "select-project":
      return {
        ...state,
        selectedProjectId: action.projectId,
        lightboxIndex: 0,
      }

    case "lightbox-prev": {
      const selected = state.projects.find((p) => p.id === state.selectedProjectId)
      if (!selected) return state
      const prevIndex =
        state.lightboxIndex <= 0
          ? selected.images.length - 1
          : state.lightboxIndex - 1
      return { ...state, lightboxIndex: prevIndex }
    }

    case "lightbox-next": {
      const selected = state.projects.find((p) => p.id === state.selectedProjectId)
      if (!selected) return state
      const nextIndex =
        state.lightboxIndex >= selected.images.length - 1
          ? 0
          : state.lightboxIndex + 1
      return { ...state, lightboxIndex: nextIndex }
    }

    case "lightbox-goto":
      return { ...state, lightboxIndex: action.index }

    case "add-project":
      return {
        ...state,
        projects: [...state.projects, action.project],
      }

    case "remove-project":
      return {
        ...state,
        projects: state.projects.filter((p) => p.id !== action.projectId),
        selectedProjectId:
          state.selectedProjectId === action.projectId
            ? null
            : state.selectedProjectId,
      }
  }
}

export const createInitialState = (projects: Project[]): GalleryState => ({
  projects,
  searchQuery: "",
  activeTag: null,
  sortBy: "date-desc",
  selectedProjectId: null,
  lightboxIndex: 0,
})

import { createSSR } from "plaited"
import type { GalleryState, GalleryAction, SortOption } from "./types"
import { loadProjects, saveProjects, sortProjects, filterProjects, getAllTags, addProject, getProject } from "./data"
import { renderGallery } from "./render"
import { reduce, createInitialState } from "./handlers"

let state: GalleryState

const init = async (): Promise<void> => {
  const projects = await loadProjects()
  state = createInitialState(projects)
}

const getFilteredProjects = (): ReturnType<typeof filterProjects> => {
  const filtered = filterProjects(state.projects, state.searchQuery, state.activeTag)
  return sortProjects(filtered, state.sortBy)
}

const dispatch = (action: GalleryAction): void => {
  state = reduce(state, action)
}

const renderPage = (): string => {
  const filtered = getFilteredProjects()
  const allTags = getAllTags(state.projects)
  const template = renderGallery(state, filtered, allTags)
  const ssr = createSSR()
  return ssr(template)
}

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const method = req.method

  // API routes
  if (url.pathname.startsWith("/api/")) {
    if (url.pathname === "/api/projects" && method === "GET") {
      const filtered = getFilteredProjects()
      return Response.json(filtered)
    }

    if (url.pathname === "/api/projects" && method === "POST") {
      const body = await req.json()
      await addProject(body)
      state = reduce(state, { type: "add-project", project: body })
      return Response.json({ ok: true })
    }

    if (url.pathname.startsWith("/api/projects/") && method === "GET") {
      const id = url.pathname.split("/").pop() ?? ""
      const project = await getProject(id)
      if (!project) return new Response("Not found", { status: 404 })
      return Response.json(project)
    }

    if (url.pathname.startsWith("/api/projects/") && method === "DELETE") {
      const id = url.pathname.split("/").pop() ?? ""
      state = reduce(state, { type: "remove-project", projectId: id })
      await saveProjects(state.projects)
      return Response.json({ ok: true })
    }

    if (url.pathname === "/api/tags" && method === "GET") {
      const tags = getAllTags(state.projects)
      return Response.json(tags)
    }

    return new Response("Not found", { status: 404 })
  }

  // UI action routes (handle p-trigger events)
  if (url.pathname === "/action" && method === "POST") {
    const body = await req.json() as { trigger: string; data?: Record<string, string> }

    switch (body.trigger) {
      case "search":
        dispatch({ type: "search", query: body.data?.value ?? "" })
        break
      case "sort":
        dispatch({ type: "sort", sortBy: (body.data?.value ?? "date-desc") as SortOption })
        break
      case "filter-tag":
        dispatch({ type: "filter-tag", tag: body.data?.tag || null })
        break
      case "select-project":
        dispatch({ type: "select-project", projectId: body.data?.projectId ?? null })
        break
      case "close-detail":
        dispatch({ type: "select-project", projectId: null })
        break
      case "lightbox-prev":
        dispatch({ type: "lightbox-prev" })
        break
      case "lightbox-next":
        dispatch({ type: "lightbox-next" })
        break
      case "lightbox-goto":
        dispatch({ type: "lightbox-goto", index: Number(body.data?.index ?? 0) })
        break
    }

    const html = renderPage()
    return new Response(html, { headers: { "Content-Type": "text/html" } })
  }

  // Default: render gallery page
  if (url.pathname === "/" || url.pathname === "") {
    const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Portfolio Gallery</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; }
    article:hover { transform: translateY(-4px); box-shadow: 0 8px 24px rgba(0,0,0,0.12) !important; }
    img { transition: opacity 0.3s; }
    a:hover { opacity: 0.85; }
  </style>
</head>
<body>
  ${renderPage()}
  <script>
    document.addEventListener('click', async (e) => {
      const el = e.target.closest('[p-trigger]');
      if (!el) return;
      const [trigger, eventType] = el.getAttribute('p-trigger').split(':');
      if (eventType !== 'click') return;
      e.preventDefault();

      const data = {};
      for (const attr of el.attributes) {
        if (attr.name.startsWith('data-')) {
          const key = attr.name.slice(5).replace(/-([a-z])/g, (_, c) => c.toUpperCase());
          data[key] = attr.value;
        }
      }

      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ trigger, data })
      });
      const html = await res.text();
      const root = document.querySelector('[p-target="gallery-root"]');
      if (root) {
        const tmp = document.createElement('div');
        tmp.innerHTML = html;
        root.replaceWith(tmp.firstElementChild || tmp);
      }
    });

    document.addEventListener('input', async (e) => {
      const el = e.target.closest('[p-trigger]');
      if (!el) return;
      const [trigger, eventType] = el.getAttribute('p-trigger').split(':');
      if (eventType !== 'input') return;

      const data = { value: el.value };
      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ trigger, data })
      });
      const html = await res.text();
      const root = document.querySelector('[p-target="gallery-root"]');
      if (root) {
        const tmp = document.createElement('div');
        tmp.innerHTML = html;
        root.replaceWith(tmp.firstElementChild || tmp);
      }
    });

    document.addEventListener('change', async (e) => {
      const el = e.target.closest('[p-trigger]');
      if (!el) return;
      const [trigger, eventType] = el.getAttribute('p-trigger').split(':');
      if (eventType !== 'change') return;

      const data = { value: el.value };
      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ trigger, data })
      });
      const html = await res.text();
      const root = document.querySelector('[p-target="gallery-root"]');
      if (root) {
        const tmp = document.createElement('div');
        tmp.innerHTML = html;
        root.replaceWith(tmp.firstElementChild || tmp);
      }
    });
  </script>
</body>
</html>`
    return new Response(html, { headers: { "Content-Type": "text/html" } })
  }

  return new Response("Not found", { status: 404 })
}

// Initialize and start server
await init()

export default {
  port: 3000,
  fetch: handleRequest,
}

export { state, dispatch, renderPage, getFilteredProjects, init }
